query GetTranscripts($fromDate: DateTime, $toDate: DateTime, $limit: Int) {
  transcripts(fromDate: $fromDate, toDate: $toDate, limit: $limit) {
    id
    title
    date
    duration
    participants
    summary {
      short_summary
      keywords
      action_items
    }
  }
}

query GetTranscript($id: String!) {
  transcript(id: $id) {
    id
    title
    date
    duration
    participants
    summary {
      short_summary
      keywords
      action_items
    }
    analytics {
      sentiments {
        positive_pct
        neutral_pct
        negative_pct
      }
    }
    sentences {
      index
      speaker_name
      text
      start_time
      end_time
    }
  }
}
